#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { float x, y, z; } Vec3;
typedef struct { Vec3 o, d; } Ray;
typedef struct { float t; Vec3 p, n; int hit; } Hit;

static Vec3 V(float x, float y, float z){ Vec3 v; v.x=x; v.y=y; v.z=z; return v; }
static Vec3 vadd(Vec3 a, Vec3 b){ return V(a.x+b.x, a.y+b.y, a.z+b.z); }
static Vec3 vsub(Vec3 a, Vec3 b){ return V(a.x-b.x, a.y-b.y, a.z-b.z); }
static Vec3 vmul(Vec3 a, float s){ return V(a.x*s, a.y*s, a.z*s); }
static float vdot(Vec3 a, Vec3 b){ return a.x*b.x + a.y*b.y + a.z*b.z; }
static float vlen(Vec3 a){ return sqrtf(a.x*a.x + a.y*a.y + a.z*a.z); }
static Vec3 vnorm(Vec3 a){ float l=vlen(a); return V(a.x/l, a.y/l, a.z/l); }
static Ray ray_create(Vec3 o, Vec3 d){ Ray r; r.o=o; r.d=vnorm(d); return r; }

static Vec3 SC;      /* sphere center */
static float SR;     /* sphere radius */
static Vec3 LIGHT;   /* normalized light direction */

static Hit sphere_intersect(Ray r, Vec3 c, float rad){
    Hit h; h.hit = 0;
    Vec3 oc = vsub(r.o, c);
    float a = vdot(r.d, r.d);
    float b = 2.0f * vdot(oc, r.d);
    float cc = vdot(oc, oc) - rad*rad;
    float disc = b*b - 4.0f*a*cc;
    if (disc < 0) return h;
    float t = (-b - sqrt(disc)) / (2.0f*a);
    if (t < 0.001f){
        t = (-b + sqrt(disc)) / (2.0f*a);
        if (t < 0.001f) return h;
    }
    h.t = t;
    h.p = vadd(r.o, vmul(r.d, t));
    h.n = vnorm(vsub(h.p, c));
    h.hit = 1;
    return h;
}

static Hit plane_intersect(Ray r, float y){
    Hit h; h.hit = 0;
    if (fabsf(r.d.y) < 1e-4f) return h;
    float t = (y - r.o.y) / r.d.y;
    if (t < 0.001f) return h;
    h.t = t;
    h.p = vadd(r.o, vmul(r.d, t));
    h.n = V(0.0f, 1.0f, 0.0f);
    h.hit = 1;
    return h;
}

static Vec3 sky_color(Ray r){
    float t = 0.5f * (r.d.y + 1.0f);
    return vadd(vmul(V(1.0f,1.0f,1.0f), 1.0f - t), vmul(V(0.5f,0.7f,1.0f), t));
}

static int is_in_shadow(Vec3 p, Vec3 light){
    Ray s = ray_create(p, light);
    return sphere_intersect(s, SC, SR).hit;
}

static Vec3 trace(Ray ray){
    Hit s = sphere_intersect(ray, SC, SR);
    Hit p = plane_intersect(ray, -1.5f);
    Hit hit; int is_sphere;
    if (s.hit && (!p.hit || s.t < p.t)){ hit = s; is_sphere = 1; }
    else if (p.hit){ hit = p; is_sphere = 0; }
    else return sky_color(ray);

    float shade;
    if (is_in_shadow(hit.p, LIGHT)) shade = 0.2f;
    else {
        float diff = fmax(vdot(hit.n, LIGHT), 0.0);
        shade = 0.8f*diff + 0.2f;
    }
    if (is_sphere) return V(shade, 0.2f*shade, 0.2f*shade);
    int q = (int)((double)floorf(hit.p.x) + (double)floorf(hit.p.z));
    float ch = (q & 1) ? 0.4f : 0.9f;
    return V(ch*shade, ch*shade, ch*shade);
}

#define W 800
#define H 600
static float img[H][W][3];

static int chan(float c){
    double d = fmin(fmax((double)c, 0.0), 1.0);
    return (int)((float)d * 255.99f);
}

int main(void){
    fprintf(stderr, "Creating high-resolution image: %dx%d\n", W, H);
    fputs("This will be downsampled with ffmpeg after rendering\n", stderr);
    LIGHT = vnorm(V(1.0f, 1.0f, -1.0f));
    SC = V(0.0f, -0.5f, -5.0f);
    SR = 1.0f;
    fputs("Rendering high-resolution image...\n", stderr);

    float aspect = (float)W / (float)H;
    for (int y = 0; y < H; y++){
        fprintf(stderr, "\rProgress: %.1f%%", (double)(100.0f*(float)y/600.0f));
        for (int x = 0; x < W; x++){
            float u = (float)x / 799.0f * (2.0f*aspect) - aspect;
            float v = 2.0f * (1.0f - (float)y / 599.0f) - 1.0f;
            Ray ray;
            ray.o = V(0.0f, 0.0f, 0.0f);
            ray.d = vnorm(V(u, v, -1.0f));
            Vec3 col = trace(ray);
            img[y][x][0] = col.x;
            img[y][x][1] = col.y;
            img[y][x][2] = col.z;
        }
    }
    fputs("\nRendering complete\n", stderr);

    FILE *f = fopen("image.ppm", "w");
    fprintf(f, "P3\n%d %d\n255\n", W, H);
    for (int y = 0; y < H; y++)
        for (int x = 0; x < W; x++)
            fprintf(f, "%d %d %d\n", chan(img[y][x][0]), chan(img[y][x][1]), chan(img[y][x][2]));
    fclose(f);
    fprintf(stderr, "Wrote image to %s\n", "image.ppm");

    fputs("Done.\n", stderr);
    return 0;
}

